PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE user_requests (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  email TEXT NOT NULL,
  requested_role TEXT NOT NULL DEFAULT 'viewer',
  initial_permissions TEXT NOT NULL DEFAULT '{}',
  status TEXT NOT NULL DEFAULT 'pending' CHECK(status IN ('pending','approved','rejected')),
  rejection_reason TEXT,
  reviewed_by TEXT,
  reviewed_at TEXT,
  initial_password_hash TEXT,
  salt TEXT,
  created_at TEXT NOT NULL
, title TEXT, department TEXT, phone TEXT, reason TEXT);
CREATE TABLE cars (
  id TEXT PRIMARY KEY,
  license_plate TEXT UNIQUE NOT NULL,
  brand TEXT,
  model TEXT,
  year INTEGER,
  color TEXT,
  fuel_type TEXT DEFAULT 'diesel',
  seat_count INTEGER DEFAULT 4,
  chassis_number TEXT,
  engine_number TEXT,
  registration_date TEXT,
  registration_expiry TEXT,
  owner_name TEXT,
  owner_address TEXT,
  status TEXT NOT NULL DEFAULT 'active' CHECK(status IN ('active','maintenance','inactive')),
  current_mileage INTEGER DEFAULT 0,
  qr_code TEXT,
  vehicle_images TEXT DEFAULT '[]',               -- JSON array of R2 keys
  registration_book_image TEXT,                   -- R2 key
  notes TEXT,
  deactivated_reason TEXT,
  deactivated_at TEXT,
  created_by TEXT,
  created_at TEXT NOT NULL,
  updated_at TEXT NOT NULL
, province TEXT DEFAULT '', vehicle_type TEXT DEFAULT '', registration_number TEXT DEFAULT '', vehicle_category TEXT DEFAULT 'primary', qr_survey_code TEXT);
CREATE TABLE vehicle_maintenance (
  id TEXT PRIMARY KEY,
  car_id TEXT NOT NULL,
  item_key TEXT NOT NULL,                         -- e.g. 'oil_change', 'tire_rotation'
  last_km INTEGER,
  last_date TEXT,
  next_km INTEGER,
  next_date TEXT,
  updated_at TEXT NOT NULL,
  UNIQUE(car_id, item_key),
  FOREIGN KEY (car_id) REFERENCES cars(id)
);
CREATE TABLE maintenance_settings (
  id TEXT PRIMARY KEY,
  item_key TEXT UNIQUE NOT NULL,
  item_name TEXT NOT NULL,
  interval_km INTEGER,
  interval_months INTEGER,
  enabled INTEGER NOT NULL DEFAULT 1,
  updated_by TEXT,
  updated_at TEXT NOT NULL
, category TEXT DEFAULT 'general', fuel_type_filter TEXT DEFAULT NULL, vehicle_class TEXT DEFAULT NULL, sort_order INTEGER DEFAULT 0, dlt_required INTEGER DEFAULT 0);
CREATE TABLE check_log (
  id TEXT PRIMARY KEY,
  car_id TEXT NOT NULL,
  inspector TEXT NOT NULL,                        -- ชื่อผู้ตรวจ
  check_type TEXT NOT NULL DEFAULT 'daily',
  overall_status TEXT NOT NULL DEFAULT 'ok' CHECK(overall_status IN ('ok','warning','critical')),
  checks_data TEXT NOT NULL DEFAULT '{}',         -- JSON: {brakes:'ok', lights:'warning', ...}
  notes TEXT,
  created_at TEXT NOT NULL,
  FOREIGN KEY (car_id) REFERENCES cars(id)
);
CREATE TABLE inspection_alerts (
  id TEXT PRIMARY KEY,
  car_id TEXT NOT NULL,
  risk_level TEXT NOT NULL DEFAULT 'medium' CHECK(risk_level IN ('low','medium','high','critical')),
  items TEXT NOT NULL DEFAULT '[]',               -- JSON array of alert items
  recommendations TEXT,
  resolved INTEGER NOT NULL DEFAULT 0,
  resolved_by TEXT,
  resolved_at TEXT,
  created_at TEXT NOT NULL,
  FOREIGN KEY (car_id) REFERENCES cars(id)
);
CREATE TABLE drivers (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  license_number TEXT,
  license_expiry TEXT,
  phone TEXT,
  status TEXT NOT NULL DEFAULT 'active' CHECK(status IN ('active','inactive','on_leave')),
  profile_image TEXT,                             -- R2 key
  id_card_image TEXT,                             -- R2 key
  fatigue_flag INTEGER NOT NULL DEFAULT 0,
  discipline_score INTEGER NOT NULL DEFAULT 100,
  notes TEXT,
  deactivated_reason TEXT,
  deactivated_at TEXT,
  created_by TEXT,
  created_at TEXT NOT NULL,
  updated_at TEXT NOT NULL
, title TEXT DEFAULT '', first_name TEXT DEFAULT '', last_name TEXT DEFAULT '', line_id TEXT DEFAULT '', position TEXT DEFAULT '', start_date TEXT, id_card_number TEXT DEFAULT '', date_of_birth TEXT, address TEXT DEFAULT '', emergency_contact TEXT DEFAULT '', emergency_phone TEXT DEFAULT '', assignment_type TEXT DEFAULT 'primary');
CREATE TABLE leaves (
  id TEXT PRIMARY KEY,
  driver_id TEXT NOT NULL,
  leave_type TEXT NOT NULL DEFAULT 'sick' CHECK(leave_type IN ('sick','personal','vacation','other')),
  start_date TEXT NOT NULL,
  end_date TEXT NOT NULL,
  reason TEXT,
  status TEXT NOT NULL DEFAULT 'pending' CHECK(status IN ('pending','approved','rejected','cancelled')),
  approved_by TEXT,
  approved_at TEXT,
  created_at TEXT NOT NULL,
  FOREIGN KEY (driver_id) REFERENCES drivers(id)
);
CREATE TABLE self_reported_fatigue (
  id TEXT PRIMARY KEY,
  driver_id TEXT NOT NULL,
  reason TEXT,
  acknowledged INTEGER NOT NULL DEFAULT 0,
  acknowledged_by TEXT,
  admin_notes TEXT,
  acknowledged_at TEXT,
  reported_at TEXT NOT NULL,
  FOREIGN KEY (driver_id) REFERENCES drivers(id)
);
CREATE TABLE queue (
  id TEXT PRIMARY KEY,
  date TEXT NOT NULL,
  time_start TEXT NOT NULL,
  time_end TEXT NOT NULL,
  car_id TEXT NOT NULL,
  driver_id TEXT NOT NULL,
  requester_id TEXT,
  requested_by TEXT,                              -- ชื่อผู้ขอ (อาจเป็นชื่อ key หรือชื่อเสรี)
  mission TEXT NOT NULL,
  destination TEXT,
  passengers INTEGER DEFAULT 1,
  status TEXT NOT NULL DEFAULT 'scheduled' CHECK(status IN ('scheduled','ongoing','completed','cancelled','frozen')),
  frozen_by TEXT,
  frozen_at TEXT,
  frozen_reason TEXT,
  cancel_reason TEXT,
  notes TEXT,
  created_by TEXT,
  created_at TEXT NOT NULL,
  updated_at TEXT NOT NULL, backup_driver_id TEXT REFERENCES drivers(id),
  FOREIGN KEY (car_id) REFERENCES cars(id),
  FOREIGN KEY (driver_id) REFERENCES drivers(id)
);
CREATE TABLE usage_records (
  id TEXT PRIMARY KEY,
  car_id TEXT NOT NULL,
  driver_id TEXT,
  record_type TEXT NOT NULL CHECK(record_type IN ('departure','return','refuel','inspection')),
  datetime TEXT NOT NULL,
  mileage INTEGER,
  location TEXT,
  notes TEXT,
  queue_id TEXT,
  created_at TEXT NOT NULL, data_quality TEXT NOT NULL DEFAULT 'normal', requester_name TEXT, is_historical INTEGER NOT NULL DEFAULT 0, auto_notes TEXT, record_source TEXT DEFAULT 'manual', purpose TEXT, destination TEXT, driver_name_manual TEXT,
  FOREIGN KEY (car_id) REFERENCES cars(id),
  FOREIGN KEY (queue_id) REFERENCES queue(id)
);
CREATE TABLE queue_rules (
  id TEXT PRIMARY KEY,
  key TEXT UNIQUE NOT NULL,
  value TEXT NOT NULL,
  updated_by TEXT,
  updated_at TEXT NOT NULL
);
CREATE TABLE fuel_log (
  id TEXT PRIMARY KEY,
  date TEXT NOT NULL,
  time TEXT,
  car_id TEXT NOT NULL,
  driver_id TEXT,
  mileage_before INTEGER,
  mileage_after INTEGER,
  liters REAL NOT NULL,
  price_per_liter REAL,
  amount REAL,
  fuel_type TEXT NOT NULL DEFAULT 'diesel',
  gas_station_name TEXT,
  gas_station_address TEXT,
  gas_station_tax_id TEXT,
  receipt_number TEXT,
  pump_meter_number TEXT,                         -- เลขหน้าตู้หัวจ่ายน้ำมัน
  receipt_image TEXT,                             -- R2 key
  receipt_pdf TEXT,                               -- R2 key
  fuel_consumption_rate REAL,                     -- km/liter
  expense_type TEXT DEFAULT 'procurement' CHECK(expense_type IN ('procurement','official_travel')),
  notes TEXT,
  created_by TEXT,
  created_at TEXT NOT NULL,
  updated_at TEXT, deleted_at TEXT, deleted_by TEXT, document_number TEXT, anomaly_flag INTEGER DEFAULT 0, purpose TEXT, purpose_detail TEXT, driver_name_manual TEXT,
  FOREIGN KEY (car_id) REFERENCES cars(id)
);
CREATE TABLE fuel_requests (
  id TEXT PRIMARY KEY,
  car_id TEXT NOT NULL,
  requester_id TEXT,
  requested_amount REAL,
  requested_liters REAL,
  reason TEXT,
  status TEXT NOT NULL DEFAULT 'pending' CHECK(status IN ('pending','approved','rejected')),
  approved_by TEXT,
  approved_at TEXT,
  created_at TEXT NOT NULL,
  FOREIGN KEY (car_id) REFERENCES cars(id)
);
CREATE TABLE scheduled_repairs (
  id TEXT PRIMARY KEY,
  car_id TEXT NOT NULL,
  repair_type TEXT NOT NULL,
  scheduled_date TEXT NOT NULL,
  status TEXT NOT NULL DEFAULT 'pending' CHECK(status IN ('pending','completed','cancelled')),
  completed_at TEXT,
  notes TEXT,
  created_by TEXT,
  created_at TEXT NOT NULL,
  FOREIGN KEY (car_id) REFERENCES cars(id)
);
CREATE TABLE tax_records (
  id TEXT PRIMARY KEY,
  car_id TEXT NOT NULL,
  tax_type TEXT NOT NULL DEFAULT 'annual_tax' CHECK(tax_type IN ('annual_tax','registration_renewal','other')),
  amount REAL,
  paid_date TEXT,
  expiry_date TEXT,
  receipt_image TEXT,                             -- R2 key
  notes TEXT,
  created_by TEXT,
  created_at TEXT NOT NULL,
  FOREIGN KEY (car_id) REFERENCES cars(id)
);
CREATE TABLE insurance_records (
  id TEXT PRIMARY KEY,
  car_id TEXT NOT NULL,
  insurance_type TEXT NOT NULL DEFAULT 'compulsory' CHECK(insurance_type IN ('compulsory','voluntary','other')),
  insurance_company TEXT,
  policy_number TEXT,
  amount REAL,
  paid_date TEXT,
  expiry_date TEXT,
  coverage_details TEXT,
  receipt_image TEXT,                             -- R2 key
  notes TEXT,
  created_by TEXT,
  created_at TEXT NOT NULL,
  FOREIGN KEY (car_id) REFERENCES cars(id)
);
CREATE TABLE audit_log (
  id TEXT PRIMARY KEY,
  user_id TEXT,
  username TEXT,
  action TEXT NOT NULL,
  module TEXT,
  entity_id TEXT,
  details TEXT,                                   -- JSON
  ip_address TEXT,
  created_at TEXT NOT NULL
);
CREATE TABLE pdpa_log (
  id TEXT PRIMARY KEY,
  user_id TEXT NOT NULL,
  accessed_user_id TEXT,
  action TEXT NOT NULL,
  data_type TEXT,
  purpose TEXT,
  created_at TEXT NOT NULL
);
CREATE TABLE notifications (
  id TEXT PRIMARY KEY,
  user_id TEXT,                                   -- NULL = broadcast to all
  type TEXT NOT NULL,
  title TEXT NOT NULL,
  message TEXT NOT NULL,
  read INTEGER NOT NULL DEFAULT 0,
  created_at TEXT NOT NULL
);
CREATE TABLE system_settings (
  id TEXT PRIMARY KEY,
  key TEXT UNIQUE NOT NULL,
  value TEXT NOT NULL,
  updated_by TEXT,
  updated_at TEXT NOT NULL
);
CREATE TABLE backups (
  id TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  module TEXT,
  row_count INTEGER DEFAULT 0,
  created_by TEXT,
  created_at TEXT NOT NULL
);
CREATE TABLE rate_limits (
  key TEXT PRIMARY KEY,
  attempts INTEGER NOT NULL DEFAULT 0,
  first_attempt_at TEXT NOT NULL,
  blocked_until TEXT
);
CREATE TABLE fuel_station_invoices (
  id TEXT PRIMARY KEY,
  invoice_number TEXT,
  station_name TEXT,
  date_from TEXT,
  date_to TEXT,
  invoice_date TEXT,
  total_amount REAL,
  invoice_image TEXT,
  status TEXT DEFAULT 'pending' CHECK(status IN ('pending','matched','mismatched','resolved')),
  notes TEXT,
  reconciled_by TEXT,
  reconciled_at TEXT,
  created_by TEXT,
  created_at TEXT NOT NULL,
  updated_at TEXT
);
CREATE TABLE fuel_invoice_items (
  id TEXT PRIMARY KEY,
  invoice_id TEXT NOT NULL,
  fuel_type TEXT,
  total_liters REAL,
  total_amount REAL,
  FOREIGN KEY (invoice_id) REFERENCES fuel_station_invoices(id)
);
CREATE TABLE IF NOT EXISTS "repair_log" (
  id TEXT PRIMARY KEY,
  car_id TEXT NOT NULL,
  date_reported TEXT NOT NULL,
  date_started TEXT,
  date_completed TEXT,
  status TEXT NOT NULL DEFAULT 'requested' CHECK(status IN (
    'requested','approved','rejected','inspected','documented','repairing','completed','cancelled'
  )),
  mileage_at_repair INTEGER,
  reporter_id TEXT,
  reporter_name TEXT,
  garage_name TEXT,
  repair_items TEXT DEFAULT '[]',
  issue_description TEXT,
  cost REAL,
  documents TEXT DEFAULT '[]',
  notes TEXT,
  created_by TEXT,
  created_at TEXT NOT NULL,
  updated_at TEXT,
  -- New columns for 7-step workflow
  approved_by TEXT,
  approved_at TEXT,
  rejected_by TEXT,
  rejected_at TEXT,
  rejection_reason TEXT,
  inspection_date TEXT,
  inspection_notes TEXT,
  quotation_documents TEXT DEFAULT '[]',
  memo_documents TEXT DEFAULT '[]',
  memo_notes TEXT,
  receipt_documents TEXT DEFAULT '[]',
  requested_by_driver_id TEXT REFERENCES drivers(id), invoice_number TEXT, work_order_number TEXT, service_type TEXT DEFAULT 'repair' CHECK(service_type IN ('scheduled_maintenance','repair','inspection','other')), labour_cost REAL DEFAULT 0, parts_cost REAL DEFAULT 0, discount_amount REAL DEFAULT 0, vat_amount REAL DEFAULT 0, grand_total REAL DEFAULT 0, mileage_out INTEGER, mechanic_name TEXT, taken_by TEXT, claim_number TEXT, insurance_company TEXT,
  FOREIGN KEY (car_id) REFERENCES cars(id)
);
CREATE TABLE vehicle_requests (
  id TEXT PRIMARY KEY,
  requester_id TEXT NOT NULL,
  requester_name TEXT NOT NULL,
  requester_department TEXT,
  date TEXT NOT NULL,
  time_start TEXT,
  time_end TEXT,
  destination TEXT NOT NULL,
  route TEXT,
  purpose TEXT,
  passengers INTEGER DEFAULT 1,
  passenger_names TEXT DEFAULT '[]',
  priority TEXT DEFAULT 'general' CHECK(priority IN ('urgent','teaching_support','general')),
  is_urgent INTEGER DEFAULT 0,
  status TEXT NOT NULL DEFAULT 'pending' CHECK(status IN ('pending','approved','rejected','cancelled')),
  approved_by TEXT,
  approved_at TEXT,
  assigned_car_id TEXT,
  assigned_driver_id TEXT,
  assigned_queue_id TEXT,
  rejection_reason TEXT,
  notes TEXT,
  pdf_generated_at TEXT,
  created_at TEXT NOT NULL,
  updated_at TEXT NOT NULL,
  FOREIGN KEY (requester_id) REFERENCES users(id),
  FOREIGN KEY (approved_by) REFERENCES users(id),
  FOREIGN KEY (assigned_car_id) REFERENCES cars(id),
  FOREIGN KEY (assigned_driver_id) REFERENCES drivers(id),
  FOREIGN KEY (assigned_queue_id) REFERENCES queue(id)
);
CREATE TABLE survey_responses (
  id TEXT PRIMARY KEY,
  car_id TEXT NOT NULL,
  queue_id TEXT,
  driver_id TEXT,
  politeness_score INTEGER CHECK(politeness_score BETWEEN 1 AND 5),
  safety_score INTEGER CHECK(safety_score BETWEEN 1 AND 5),
  punctuality_score INTEGER CHECK(punctuality_score BETWEEN 1 AND 5),
  cleanliness_score INTEGER CHECK(cleanliness_score BETWEEN 1 AND 5),
  appearance_score INTEGER CHECK(appearance_score BETWEEN 1 AND 5),
  overall_score INTEGER CHECK(overall_score BETWEEN 1 AND 5),
  comment TEXT,
  respondent_name TEXT,
  created_at TEXT NOT NULL,
  FOREIGN KEY (car_id) REFERENCES cars(id),
  FOREIGN KEY (queue_id) REFERENCES queue(id),
  FOREIGN KEY (driver_id) REFERENCES drivers(id)
);
CREATE TABLE incidents (
  id TEXT PRIMARY KEY,
  car_id TEXT NOT NULL,
  driver_id TEXT,
  incident_date TEXT NOT NULL,
  incident_type TEXT NOT NULL CHECK(incident_type IN ('accident','traffic_violation','damage','other')),
  description TEXT,
  location TEXT,
  damage_cost REAL DEFAULT 0,
  photos TEXT DEFAULT '[]',
  police_report_number TEXT,
  insurance_claim TEXT,
  status TEXT NOT NULL DEFAULT 'reported' CHECK(status IN ('reported','investigating','resolved','closed')),
  resolved_by TEXT,
  resolved_at TEXT,
  resolution_notes TEXT,
  created_by TEXT,
  created_at TEXT NOT NULL,
  updated_at TEXT, incident_time TEXT, notes TEXT,
  FOREIGN KEY (car_id) REFERENCES cars(id),
  FOREIGN KEY (driver_id) REFERENCES drivers(id),
  FOREIGN KEY (created_by) REFERENCES users(id)
);
CREATE TABLE inspection_records (
  id TEXT PRIMARY KEY,
  car_id TEXT NOT NULL,
  inspection_date TEXT NOT NULL,
  expiry_date TEXT NOT NULL,
  inspection_center TEXT,
  result TEXT CHECK(result IN ('passed','failed')),
  cost REAL,
  certificate_image TEXT,
  notes TEXT,
  created_by TEXT,
  created_at TEXT NOT NULL,
  FOREIGN KEY (car_id) REFERENCES cars(id)
);
CREATE TABLE trip_evaluations (
  id TEXT PRIMARY KEY,
  queue_id TEXT NOT NULL,
  evaluator_id TEXT NOT NULL,
  driver_behavior_score INTEGER CHECK(driver_behavior_score BETWEEN 1 AND 5),
  vehicle_condition_score INTEGER CHECK(vehicle_condition_score BETWEEN 1 AND 5),
  punctuality_score INTEGER CHECK(punctuality_score BETWEEN 1 AND 5),
  overall_score INTEGER CHECK(overall_score BETWEEN 1 AND 5),
  problems TEXT,
  suggestions TEXT,
  created_at TEXT NOT NULL,
  FOREIGN KEY (queue_id) REFERENCES queue(id),
  FOREIGN KEY (evaluator_id) REFERENCES users(id)
);
CREATE TABLE repair_items (
  id TEXT PRIMARY KEY,
  repair_id TEXT NOT NULL,
  part_code TEXT,
  description TEXT NOT NULL,
  brand_condition TEXT,
  quantity REAL DEFAULT 1,
  unit_price REAL DEFAULT 0,
  discount_percent REAL DEFAULT 0,
  discount_amount REAL DEFAULT 0,
  net_amount REAL DEFAULT 0,
  item_type TEXT DEFAULT 'part' CHECK(item_type IN ('part','labour','service','other')),
  sort_order INTEGER DEFAULT 0,
  created_at TEXT NOT NULL,
  FOREIGN KEY (repair_id) REFERENCES repair_log(id) ON DELETE CASCADE
);
CREATE TABLE maintenance_profiles (
  id TEXT PRIMARY KEY,
  brand TEXT NOT NULL,
  model TEXT DEFAULT '*',
  item_key TEXT NOT NULL,
  interval_km INTEGER,
  interval_months INTEGER,
  notes TEXT,
  updated_at TEXT NOT NULL,
  UNIQUE(brand, model, item_key)
);
CREATE TABLE maintenance_vehicle_profiles (
  id TEXT PRIMARY KEY,
  car_id TEXT NOT NULL,
  item_key TEXT NOT NULL,
  interval_km INTEGER,
  interval_months INTEGER,
  notes TEXT,
  updated_at TEXT NOT NULL,
  UNIQUE(car_id, item_key)
);
CREATE TABLE d1_migrations(
		id         INTEGER PRIMARY KEY AUTOINCREMENT,
		name       TEXT UNIQUE,
		applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE TABLE users (
  id TEXT PRIMARY KEY,
  username TEXT UNIQUE NOT NULL,
  email TEXT UNIQUE NOT NULL,
  password_hash TEXT NOT NULL,
  salt TEXT NOT NULL,
  role TEXT NOT NULL DEFAULT 'viewer' CHECK(role IN ('admin','super_admin','vehicle','fuel','repair','viewer','manager','driver','staff')),
  permissions TEXT NOT NULL DEFAULT '{}',
  title TEXT,
  first_name TEXT NOT NULL,
  last_name TEXT NOT NULL,
  display_name TEXT,
  phone TEXT,
  profile_image TEXT,
  driver_id TEXT,
  active INTEGER NOT NULL DEFAULT 1,
  pdpa_accepted INTEGER NOT NULL DEFAULT 0,
  pdpa_accepted_at TEXT,
  must_change_password INTEGER NOT NULL DEFAULT 1,
  last_login TEXT,
  created_at TEXT NOT NULL,
  updated_at TEXT NOT NULL
);
CREATE TABLE sessions (
  id TEXT PRIMARY KEY,
  user_id TEXT NOT NULL,
  token TEXT UNIQUE NOT NULL,
  expires_at TEXT NOT NULL,
  created_at TEXT NOT NULL,
  is_impersonated INTEGER NOT NULL DEFAULT 0,
  impersonator_id TEXT,
  FOREIGN KEY (user_id) REFERENCES users(id)
);
CREATE TABLE password_history (
  id TEXT PRIMARY KEY,
  user_id TEXT NOT NULL,
  password_hash TEXT NOT NULL,
  salt TEXT NOT NULL,
  changed_at TEXT NOT NULL,
  FOREIGN KEY (user_id) REFERENCES users(id)
);
CREATE TABLE reset_password_requests (
  id TEXT PRIMARY KEY,
  user_id TEXT NOT NULL,
  email TEXT NOT NULL,
  token TEXT UNIQUE NOT NULL,
  expires_at TEXT NOT NULL,
  used INTEGER NOT NULL DEFAULT 0,
  created_at TEXT NOT NULL,
  FOREIGN KEY (user_id) REFERENCES users(id)
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_queue_date ON queue(date);
CREATE INDEX idx_queue_car_id ON queue(car_id);
CREATE INDEX idx_queue_driver_id ON queue(driver_id);
CREATE INDEX idx_fuel_log_car_id ON fuel_log(car_id);
CREATE INDEX idx_fuel_log_date ON fuel_log(date);
CREATE INDEX idx_audit_log_created_at ON audit_log(created_at);
CREATE INDEX idx_notifications_user_id ON notifications(user_id);
CREATE INDEX idx_notifications_read ON notifications(read);
CREATE INDEX idx_tax_records_car_id ON tax_records(car_id);
CREATE INDEX idx_insurance_records_car_id ON insurance_records(car_id);
CREATE INDEX idx_check_log_car_id ON check_log(car_id);
CREATE INDEX idx_usage_records_car_id ON usage_records(car_id);
CREATE INDEX idx_queue_status ON queue(status);
CREATE INDEX idx_queue_status_date_car ON queue(status, date, car_id);
CREATE INDEX idx_fuel_log_car_date ON fuel_log(car_id, date DESC);
CREATE INDEX idx_audit_log_user_id ON audit_log(user_id);
CREATE INDEX idx_audit_log_user_date ON audit_log(user_id, created_at DESC);
CREATE INDEX idx_usage_records_driver_id ON usage_records(driver_id);
CREATE INDEX idx_usage_records_datetime ON usage_records(datetime DESC);
CREATE INDEX idx_usage_records_quality ON usage_records(data_quality);
CREATE INDEX idx_check_log_created_at ON check_log(created_at);
CREATE INDEX idx_leaves_driver_id ON leaves(driver_id);
CREATE INDEX idx_fuel_log_deleted ON fuel_log(deleted_at);
CREATE INDEX idx_fuel_log_document_number ON fuel_log(document_number);
CREATE INDEX idx_fuel_log_date_car ON fuel_log(date, car_id);
CREATE INDEX idx_repair_log_car_id ON repair_log(car_id);
CREATE INDEX idx_repair_log_status ON repair_log(status);
CREATE INDEX idx_repair_log_driver ON repair_log(requested_by_driver_id);
CREATE INDEX idx_vehicle_requests_status ON vehicle_requests(status);
CREATE INDEX idx_vehicle_requests_requester ON vehicle_requests(requester_id);
CREATE INDEX idx_vehicle_requests_date ON vehicle_requests(date);
CREATE INDEX idx_survey_car_id ON survey_responses(car_id);
CREATE INDEX idx_survey_driver_id ON survey_responses(driver_id);
CREATE INDEX idx_survey_created_at ON survey_responses(created_at);
CREATE INDEX idx_incidents_car_id ON incidents(car_id);
CREATE INDEX idx_incidents_driver_id ON incidents(driver_id);
CREATE INDEX idx_incidents_date ON incidents(incident_date);
CREATE INDEX idx_inspection_car_id ON inspection_records(car_id);
CREATE INDEX idx_inspection_expiry ON inspection_records(expiry_date);
CREATE INDEX idx_trip_eval_queue ON trip_evaluations(queue_id);
CREATE INDEX idx_trip_eval_evaluator ON trip_evaluations(evaluator_id);
CREATE INDEX idx_repair_items_repair_id ON repair_items(repair_id);
CREATE INDEX idx_repair_log_invoice ON repair_log(invoice_number);
CREATE INDEX idx_repair_log_service_type ON repair_log(service_type);
CREATE INDEX idx_mp_brand ON maintenance_profiles(brand);
CREATE INDEX idx_mp_item ON maintenance_profiles(item_key);
CREATE INDEX idx_mvp_car ON maintenance_vehicle_profiles(car_id);
CREATE INDEX idx_mvp_item ON maintenance_vehicle_profiles(item_key);
CREATE INDEX idx_inspection_alerts_resolved_created_at
ON inspection_alerts(resolved, created_at DESC);
CREATE INDEX idx_inspection_alerts_car_resolved_created_at
ON inspection_alerts(car_id, resolved, created_at DESC);
CREATE INDEX idx_check_log_car_created_at
ON check_log(car_id, created_at DESC);
CREATE INDEX idx_usage_records_source ON usage_records(record_source);
